// RemoteUI is the resolver for the remoteUI field.
//
// It combines the tenant-owned URL templates (origin + path layout) with the
// bundle slug/version read from the execution's pinned Worker Deployment
// Version, and forwards the rendered URLs as-is. The composition happens in the
// workflow client (RenderRemoteUI), not here.
func (r *queryResolver) RemoteUI(ctx context.Context, input model.RemoteUIQueryInput) (*commonworkflow.UIBundleURLs, error) {
	req := request.ForContext(ctx)
	tenantID, err := singleTenantID(req)
	if err != nil {
		return nil, err
	}

	workflowClient, err := r.workflowRouter.GetClient(ctx, tenantID.String())
	if err != nil || workflowClient == nil {
		return nil, ErrInvalidWorkflowClient
	}

	tenant, err := r.tenantUITemplates(ctx, tenantID)
	if err != nil {
		return nil, err
	}

	render := commonworkflow.UITemplateContext{
		TenantID: tenantID.String(),
		Flavour:  tenant.Flavour,
		Env:      r.remoteUIDefaults.Env,
	}
	return workflowClient.RenderRemoteUI(ctx, input.WorkflowID, input.WorkflowExecutionID, tenant.Templates, render, r.remoteUIDefaults.Bundle)
}

// WorkerDeploymentUIBundles is the resolver for the workerDeploymentUIBundles field.
//
// Lists every Worker Deployment Version in the tenant's namespace with its
// drainage status and the UI bundle it ships, for drain visibility. This is an
// operator view (build IDs + drainage status), so it is gated behind the admin
// role. The full (cached) listing is paginated in memory.
func (r *queryResolver) WorkerDeploymentUIBundles(ctx context.Context, first *int, after *string) (*model.DeploymentVersionUIConnection, error) {
	req := request.ForContext(ctx)
	tenantID, err := singleTenantID(req)
	if err != nil {
		return nil, err
	}
	if !req.User().HasRole(authn.ROLE_ADMIN, tenantID) {
		return nil, ErrAdminRoleRequired
	}

	workflowClient, err := r.workflowRouter.GetClient(ctx, tenantID.String())
	if err != nil || workflowClient == nil {
		return nil, ErrInvalidWorkflowClient
	}

	versions, err := workflowClient.ListDeploymentVersionUIBundles(ctx)
	if err != nil {
		return nil, err
	}

	return paginateDeploymentVersionUIBundles(versions, first, after), nil
}
